using CollegeManagementSystem.Data;using CollegeManagementSystem.Data.Entities;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Controllers;[Route("api/[controller]")][ApiController]public class InstructorsController(AppDbContext db) : ControllerBase{    [HttpGet]    public async Task<IActionResult> GetInstructors()    {        var instructors = await db.Instructors.ToListAsync();        return Ok(instructors);    }    [HttpGet("{id}")]    public async Task<IActionResult> GetInstructorById(int id)    {        var instructor = await db.Instructors.Where(i => i.Id == id).ToListAsync();        return Ok(instructor);    }    [HttpPost]    public async Task<IActionResult> AddInstructor(Instructor instructor)    {        await db.Instructors.AddAsync(instructor);        await db.SaveChangesAsync();        return Ok(instructor);    }}